#include<bits/stdc++.h>
using namespace std;

vector<int> a[100001];

int n, m, num;
int v[100001]={0};
int maxt;
void dfs(int x, int d) {
	if(v[x]) return; 
	v[x] = d;
	for(int i=0; i<a[x].size(); i++)
		dfs(a[x][i], d);
}
int main() {
    ios::sync_with_stdio(0);
	cin.tie(0);cout.tie(0); 
	cin >> n >> m;
	for (int i = 1; i <= m; i++) {
		int x, y;
		cin >> x >> y;
		a[y].push_back(x);
	}
    for(int i=n;i;i--){
		dfs(i,i);

	}for(int i=1;i<=n;i++){
			cout<<v[i]<<" ";

		}

	return 0;
}
